    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes;
    private readonly Dictionary<int, List<int>> _ratings = new();
    private int _nextId;

    public RecipeService()
    {
        _recipes = new List<Recipe>
        {
            new() { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Basil, Olive oil", Steps = "1. Preheat oven to 475°F\n2. Roll out dough\n3. Spread crushed tomatoes\n4. Add torn mozzarella\n5. Bake 10-12 minutes\n6. Top with fresh basil" },
            new() { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook pasta al dente\n2. Crisp guanciale in a pan\n3. Whisk eggs with pecorino\n4. Toss hot pasta with guanciale\n5. Remove from heat, add egg mixture\n6. Toss until creamy" },
            new() { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Cream, Ginger, Garlic", Steps = "1. Marinate chicken in spiced yogurt\n2. Grill or broil chicken pieces\n3. Sauté onions, ginger, garlic\n4. Add tomato sauce and spices\n5. Simmer, add cream\n6. Add chicken and heat through" },
            new() { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Tofu, Bean sprouts, Peanuts, Tamarind paste, Fish sauce, Lime", Steps = "1. Soak rice noodles\n2. Press and cube tofu, fry until golden\n3. Mix tamarind, fish sauce, sugar for sauce\n4. Stir-fry vegetables\n5. Add noodles and sauce\n6. Top with peanuts and lime" },
            new() { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco seasoning, Corn tortillas, Lettuce, Tomato, Cheese, Sour cream", Steps = "1. Brown ground beef\n2. Add taco seasoning and water\n3. Simmer until thickened\n4. Warm tortillas\n5. Assemble with toppings\n6. Serve with lime wedges" },
            new() { Id = 6, Title = "Miso Ramen", Category = "Japanese", Ingredients = "Ramen noodles, Miso paste, Pork belly, Soft-boiled egg, Green onions, Nori, Corn", Steps = "1. Make broth with miso and dashi\n2. Slice and sear pork belly\n3. Cook ramen noodles\n4. Prepare soft-boiled eggs\n5. Assemble bowls with broth and noodles\n6. Top with pork, egg, and garnishes" },
            new() { Id = 7, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Cilantro, Red onion, Jalapeño, Tomato, Salt", Steps = "1. Halve and pit avocados\n2. Mash to desired consistency\n3. Dice onion, jalapeño, tomato\n4. Mix all ingredients\n5. Season with salt and lime\n6. Serve immediately with chips" },
            new() { Id = 8, Title = "Green Curry", Category = "Thai", Ingredients = "Green curry paste, Coconut milk, Chicken, Thai basil, Bamboo shoots, Fish sauce", Steps = "1. Fry curry paste in coconut cream\n2. Add sliced chicken\n3. Pour in coconut milk\n4. Add bamboo shoots and vegetables\n5. Season with fish sauce and sugar\n6. Finish with Thai basil" },
        };
        _nextId = 9;
    }

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipe(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();
        _ratings[recipeId].Add(stars);

        var recipe = GetRecipe(recipeId);
        if (recipe is not null)
        {
            recipe.RatingCount = _ratings[recipeId].Count;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps
        });
    }
}

