@rendermode InteractiveServer

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _currentRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">★</span>
    }
    @if (RatingCount > 0)
    {
        <span class="rating-info ms-2 text-muted">
            (@AverageRating.ToString("0.0") avg, @RatingCount ratings)
        </span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double AverageRating { get; set; }
    [Parameter] public int RatingCount { get; set; }
    [Parameter] public EventCallback<int> OnRated { get; set; }

    private int _currentRating;

    private async Task Rate(int stars)
    {
        _currentRating = stars;
        await OnRated.InvokeAsync(stars);
    }
}

