@page "/recipes/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@using RecipeCommunity.Models
@using System.ComponentModel.DataAnnotations

<PageTitle>Submit a Recipe</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1>📝 Submit a Recipe</h1>
    <p class="text-muted">Share your favorite recipe with the community!</p>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>🎉 Recipe submitted successfully!</h4>
            <p>Your recipe "<strong>@_model.Title</strong>" has been added to the @_model.Category category.</p>
            <a href="/recipes/category/@_model.Category" class="btn btn-primary">View Category</a>
            <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
        </div>
    }
    else
    {
        <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger" />

            <div class="mb-3">
                <label for="title" class="form-label">Recipe Title</label>
                <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g., Grandma's Apple Pie" />
                <ValidationMessage For="() => _model.Title" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="category" class="form-label">Category</label>
                <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                    <option value="">-- Select a category --</option>
                    @foreach (var cat in _categories)
                    {
                        <option value="@cat">@cat</option>
                    }
                    <option value="Other">Other</option>
                </InputSelect>
                <ValidationMessage For="() => _model.Category" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="ingredients" class="form-label">Ingredients</label>
                <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="_model.Ingredients"
                               placeholder="Comma-separated list: Flour, Sugar, Butter, Eggs..." />
                <ValidationMessage For="() => _model.Ingredients" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="_model.Steps"
                               placeholder="One step per line:&#10;1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
                <ValidationMessage For="() => _model.Steps" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Recipe</button>
        </EditForm>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private RecipeFormModel _model = new();
    private IReadOnlyList<string> _categories = [];
    private bool _submitted;

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private void HandleSubmit()
    {
        RecipeService.SubmitRecipe(new RecipeSubmission
        {
            Title = _model.Title,
            Category = _model.Category,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        });
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }

    private class RecipeFormModel
    {
        [Required(ErrorMessage = "Please enter a recipe title.")]
        [StringLength(100, MinimumLength = 3)]
        public string Title { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please select a category.")]
        public string Category { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please list the ingredients.")]
        public string Ingredients { get; set; } = string.Empty;

        [Required(ErrorMessage = "Please describe the steps.")]
        public string Steps { get; set; } = string.Empty;
    }
}

