@page "/recipes/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@CategoryName Recipes</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1>@CategoryName Recipes</h1>

    @if (_recipes.Count == 0)
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
    else
    {
        <div class="row row-cols-1 row-cols-md-2 g-4">
            @foreach (var recipe in _recipes)
            {
                <div class="col">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="card-text text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("0.0") (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="/recipes/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<Recipe> _recipes = [];

    protected override void OnInitialized()
    {
        _recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

