@page "/"
@using RecipeCommunity.Services

<PageTitle>Recipe Community</PageTitle>

<div class="container">
    <div class="text-center my-4">
        <h1>🍳 Recipe Community</h1>
        <p class="lead">Discover and share delicious recipes from around the world</p>
    </div>

    <h2 class="mb-3">Browse by Category</h2>
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var category in _categories)
        {
            <div class="col">
                <div class="card h-100 shadow-sm">
                    <div class="card-body text-center">
                        <h4 class="card-title">@GetEmoji(category) @category</h4>
                        <p class="card-text text-muted">
                            @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                        </p>
                        <a href="/recipes/category/@category" class="btn btn-outline-primary">
                            View Recipes
                        </a>
                    </div>
                </div>
            </div>
        }
    </div>

    <div class="text-center mt-5">
        <a href="/recipes/submit" class="btn btn-success btn-lg">📝 Submit a Recipe</a>
    </div>
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> _categories = [];

    protected override void OnInitialized()
    {
        _categories = RecipeService.GetCategories();
    }

    private static string GetEmoji(string category) => category switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Thai" => "🥘",
        "Mexican" => "🌮",
        "Japanese" => "🍜",
        _ => "🍽️"
    };
}

