                    {
                        <li>@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-header"><h4 class="mb-0">👨‍🍳 Steps</h4></div>
            <div class="card-body">
                @foreach (var step in _recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                {
                    <p>@step</p>
                }
            </div>
        </div>
    }
</div>

